    def publish_message(self, user_data, message_attributes=None):
        """
        Publishes a user data message to the SQS queue.
        This method is designed to handle PII data. Ensure appropriate
        security measures (e.g., KMS encryption for SQS, IAM policies)
        are in place for the queue and your application.

        Args:
            user_data (dict): A dictionary containing user data, potentially
                              including PII like 'email', 'phone_number', 'address'.
                              Example:
                              {
                                  "user_id": "user123",
                                  "name": "John Doe",
                                  "email": "john.doe@example.com",
                                  "phone_number": "+15551234567",
                                  "address": "123 Main St, Anytown, USA",
                                  "opt_in_marketing": True
                              }
            message_attributes (dict, optional): A dictionary of message attributes.
                                                Defaults to None.
                                                Example:
                                                {
                                                    'MessageType': {
                                                        'DataType': 'String',
                                                        'StringValue': 'UserData'
                                                    },
                                                    'DataSensitivity': {
                                                        'DataType': 'String',
                                                        'StringValue': 'PII_HIGH'
                                                    }
                                                }

        Returns:
            dict: The response from the SQS send_message API call, or None if an error occurs.
        """
        if not isinstance(user_data, dict):
            logging.error("user_data must be a dictionary.")
            return None

        message_body = json.dumps(user_data)

        try:
            response = self.sqs_client.send_message(
                QueueUrl=self.queue_url,
                MessageBody=message_body,
                MessageAttributes=message_attributes if message_attributes else {}
            )
            logging.info(f"Message sent to SQS queue {self.queue_url}. MessageId: {response.get('MessageId')}")
            return response
        except Exception as e:
            logging.error(f"Error sending message to SQS queue {self.queue_url}: {e}")
            return None

